<?php require_once 'config.php'; if (!isset($_SESSION['user_id'])) { http_response_code(403); die("Acceso denegado"); } $user_id = $_SESSION['user_id']; $db = getDB(); if ($_SERVER['REQUEST_METHOD'] === 'POST') { $action = $_POST['action'] ?? null; if ($action === 'crear') { $var_name = $_POST['variable_name'] ?? ''; $var_value = $_POST['variable_value'] ?? ''; $var_type = $_POST['variable_type'] ?? 'text'; $stmt = $db->prepare("INSERT INTO whatsapp_custom_variables (reseller_id, variable_name, variable_value, variable_type, is_active) VALUES (?, ?, ?, ?, 1)"); $stmt->execute([$user_id, $var_name, $var_value, $var_type]); $_SESSION['success'] = "Variable creada correctamente"; } elseif ($action === 'actualizar') { $var_id = $_POST['variable_id'] ?? 0; $var_value = $_POST['variable_value'] ?? ''; $stmt = $db->prepare("UPDATE whatsapp_custom_variables SET variable_value = ? WHERE id = ? AND reseller_id = ?"); $stmt->execute([$var_value, $var_id, $user_id]); $_SESSION['success'] = "Variable actualizada"; } elseif ($action === 'toggle') { $var_id = $_POST['variable_id'] ?? 0; $stmt = $db->prepare("UPDATE whatsapp_custom_variables SET is_active = NOT is_active WHERE id = ? AND reseller_id = ?"); $stmt->execute([$var_id, $user_id]); $_SESSION['success'] = "Estado actualizado"; } header("Location: variables_whatsapp.php"); exit; } $stmt = $db->prepare("SELECT * FROM whatsapp_custom_variables WHERE reseller_id = ? ORDER BY created_at DESC"); $stmt->execute([$user_id]); $variables = $stmt->fetchAll(PDO::FETCH_ASSOC); ?> <!DOCTYPE html> <html lang="es"> <head> <meta charset="UTF-8"> <meta name="viewport" content="width=device-width, initial-scale=1.0"> <title>Variables Personalizadas WhatsApp</title>title> <style> * { margin: 0; padding: 0; box-sizing: border-box; } body { font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); min-height: 100vh; padding: 20px; } .container { max-width: 1000px; margin: 0 auto; background: white; border-radius: 10px; padding: 30px; box-shadow: 0 10px 40px rgba(0,0,0,0.2); } h1 { color: #667eea; margin-bottom: 30px; } .form-group { margin-bottom: 15px; } label { display: block; margin-bottom: 5px; font-weight: 600; } input, select, textarea { width: 100%; padding: 10px; border: 1px solid #ddd; border-radius: 5px; font-size: 14px; } button { background: #667eea; color: white; padding: 10px 20px; border: none; border-radius: 5px; cursor: pointer; font-weight: 600; } button:hover { background: #5568d3; } .variables-list { margin-top: 30px; } .var-card { background: #f9f9f9; padding: 15px; border-radius: 5px; margin-bottom: 10px; display: flex; justify-content: space-between; align-items: center; border-left: 4px solid #667eea; } .var-name { font-weight: 600; color: #333; } .var-value { color: #666; font-size: 14px; margin-top: 5px; } .actions { display: flex; gap: 10px; } .btn-sm { padding: 5px 10px; font-size: 12px; } .alert { padding: 15px; border-radius: 5px; margin-bottom: 20px; } .alert.success { background: #d4edda; color: #155724; } </style> </head>head> <body> <div class="container"> <h1>⚙️ Variables Personalizadas</h1>h1> <?php if (isset($_SESSION['success'])): ?> <div class="alert success"><?php echo $_SESSION['success']; unset($_SESSION['success']); ?></div> <?php endif; ?> <form method="POST"> <h3>Crear Nueva Variable</h3>h3> <div class="form-group"> <label>Nombre de la variable:</label>label> <input type="text" name="variable_name" placeholder="{descuento_porcentaje}" required> </div>div> <div class="form-group"> <label>Valor:</label>label> <input type="text" name="variable_value" placeholder="10%" required> </div>div> <div class="form-group"> <label>Tipo:</label>label> <select name="variable_type"> <option value="text">Texto</option>option> <option value="number">Número</option>option> <option value="date">Fecha</option>option> <option value="email">Email</option>option> </select>select> </div>div> <button type="submit" name="action" value="crear">Crear Variable</button>button> </form>form> <div class="variables-list"> <h3>Mis Variables</h3>h3> <?php foreach ($variables as $var): ?> <div class="var-card"> <div> <div class="var-name"><?php echo htmlspecialchars($var['variable_name']); ?></div> <div class="var-value"><?php echo htmlspecialchars($var['variable_value']); ?></div> <small><?php echo ucfirst($var['variable_type']); ?></small> </div>div> <div class="actions"> <form method="POST" style="display:inline;"> <input type="hidden" name="action" value="actualizar"> <input type="hidden" name="variable_id" value="<?php echo $var['id']; ?>"> <input type="text" name="variable_value" value="<?php echo htmlspecialchars($var['variable_value']); ?>" style="width: 150px; margin-right: 5px;"> <button type="submit" class="btn-sm">Actualizar</button>button> </form>form> <form method="POST" style="display:inline;"> <input type="hidden" name="action" value="toggle"> <input type="hidden" name="variable_id" value="<?php echo $var['id']; ?>"> <button type="submit" class="btn-sm" style="background: <?php echo $var['is_active'] ? '#4caf50' : '#999'; ?>"><?php echo $var['is_active'] ? 'Activo' : 'Inactivo'; ?></button> </form>form> </div>div> </div>div> <?php endforeach; ?> </div>div> </div>div> </body>body> </html>html></style></title></head>
